UPDATE esg.tb_risk_assessment_organ_chart_orgn_role
   SET orgn_role_nm = #{orgnRoleNm},
       remark = #{remark},
	   ord_seq = #{ordSeq},
	   use_yn = #{useYn},
	   updated_at = now(),
	   updated_by = #{updatedBy}
 WHERE comp_id = #{compId}
   AND orgn_role_id = #{orgnRoleId}

mapper.select:
select tab1.hr_id, tab1.hr_nm, tab1.jbrp, tab1.part_comp_id, tab1.orgn_id, tab1.ord_seq, tab1.use_yn from esg.tb_hr_info tab1 inner join esg.tb_hr_info_comp_map tab2 on tab1.hr_id = tab2.hr_id and tab2.comp_id = #{compId} where tab1.use_yn = 'Y'
and tab1.orgn_id = #{orgnId}
order by tab1.ord_seq asc

